const labelPriority = ['!Completed', 'To Do/Done', '!Waiting', '!In Progress', 'To Do', '!New Case'];
const labelRows = $items('Build Case Label Map', 0, 0).map((item) => item.json ?? {});
const threadMap = new Map();
let currentSource = null;
for (const item of items) {
  const threadId = String(item.json?.id ?? item.json?.thread_id ?? '').trim();
  if (!threadId) continue;
  const pairedIndex = Number.isInteger(item.pairedItem?.item) ? item.pairedItem.item : null;
  const explicitSource = pairedIndex !== null ? (labelRows[pairedIndex] ?? null) : null;
  const explicitLabelName = String(explicitSource?.label_name ?? '').trim();
  const explicitLabelId = String(explicitSource?.label_id ?? '').trim();
  if (explicitLabelName) {
    currentSource = {
      label_name: explicitLabelName,
      label_id: explicitLabelId,
    };
  }
  const source = currentSource ?? { label_name: '', label_id: '' };
  const sourceLabelName = String(source.label_name ?? '').trim();
  const sourceLabelId = String(source.label_id ?? '').trim();
  const existing = threadMap.get(threadId) ?? {
    thread_id: threadId,
    label_names: [],
    label_ids: [],
  };
  if (sourceLabelName && !existing.label_names.includes(sourceLabelName)) existing.label_names.push(sourceLabelName);
  if (sourceLabelId && !existing.label_ids.includes(sourceLabelId)) existing.label_ids.push(sourceLabelId);
  threadMap.set(threadId, existing);
}
return [...threadMap.values()].map((entry) => {
  const labelName = labelPriority.find((name) => entry.label_names.includes(name)) || entry.label_names[0] || '';
  const labelIndex = entry.label_names.indexOf(labelName);
  const labelId = labelIndex >= 0 ? (entry.label_ids[labelIndex] || entry.label_ids[0] || '') : (entry.label_ids[0] || '');
  return {
    json: {
      thread_id: entry.thread_id,
      label_name: labelName,
      label_id: labelId,
      label_names: entry.label_names,
      label_ids: entry.label_ids,
    },
  };
});

const source = $items('Unique Threads', 0, 0)[$itemIndex]?.json ?? {};
const settings = $('Load Sync Settings').first()?.json ?? {};
const thread = $json ?? {};
const labelRows = $items('Build Case Label Map', 0, 0).map((item) => item.json ?? {});
const labelIdToName = Object.fromEntries(
  labelRows
    .map((row) => [String(row.label_id ?? '').trim(), String(row.label_name ?? '').trim()])
    .filter(([id, name]) => id && name),
