);
const labelStatusMap = {
  '!New Case': 'New',
  '!In Progress': 'In Progress',
  '!Waiting': 'Waiting',
  '!Completed': 'Completed',
  'To Do': 'New',
  'To Do/Done': 'Completed',
};
const labelPriority = ['!Completed', 'To Do/Done', '!Waiting', '!In Progress', 'To Do', '!New Case'];
const threadLabelNames = new Set();
const registerLabelName = (value) => {
  const raw = typeof value === 'string'
    ? value
    : (value?.name ?? value?.id ?? '');
  const normalized = String(raw ?? '').trim();
  if (!normalized) return;
  const resolved = labelIdToName[normalized] || normalized;
  if (knownLabelNames.has(resolved)) threadLabelNames.add(resolved);
};
registerLabelName(source.label_name);
registerLabelName(source.label_id);
for (const label of Array.isArray(source.label_names) ? source.label_names : []) registerLabelName(label);
for (const labelId of Array.isArray(source.label_ids) ? source.label_ids : []) registerLabelName(labelId);
for (const label of thread.labels ?? []) registerLabelName(label);
for (const message of thread.messages ?? []) {
  for (const label of message?.labels ?? []) registerLabelName(label);
  for (const labelId of message?.labelIds ?? []) registerLabelName(labelId);
}
const labelName = labelPriority.find((name) => threadLabelNames.has(name)) || String(source.label_name ?? '').trim();
const status = labelStatusMap[labelName] || 'New';
const internalEmailCandidates = [
  settings.email_reply_to,
  'members.avondaleltc@gmail.com',
];
const normalizeEmail = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return '';
  const angle = raw.match(/<([^>]+)>/);
  if (angle?.[1]) return angle[1].trim().toLowerCase();
  const plain = raw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return plain?.[0]?.trim().toLowerCase() || raw.toLowerCase();
};
const internalEmails = new Set(internalEmailCandidates.map(normalizeEmail).filter(Boolean));
const sqlLiteral = (value) => {
  if (value === null || value === undefined) return 'NULL';
  const parts = String(value)
    .split('$')
    .map((part) => `'${part.replace(/'/g, "''")}'`);
  if (parts.length === 1) return parts[0];
  return `CONCAT(${parts.flatMap((part, index) => (index === 0 ? [part] : ['chr(36)', part])).join(', ')})`;
};
const jsonLiteral = (value) => sqlLiteral(JSON.stringify(value));
const decodeBase64Url = (value) => {
  if (!value) return '';
  const normalized = String(value).replace(/-/g, '+').replace(/_/g, '/');
  const padded = normalized + '='.repeat((4 - (normalized.length % 4 || 4)) % 4);
  const buffer = Buffer.from(padded, 'base64');
  const utf8 = buffer.toString('utf8');
  if (!utf8.includes('\uFFFD')) return utf8;
  return buffer.toString('latin1');
};
const cleanText = (value) => String(value ?? '').replace(/\r\n/g, '\n').replace(/\u00a0/g, ' ').trim();
const stripHtml = (value) => cleanText(String(value ?? '')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/p>/gi, '\n\n')
  .replace(/<\/div>/gi, '\n')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&lt;/gi, '<')
  .replace(/&gt;/gi, '>')
  .replace(/&quot;/gi, '"')
  .replace(/&#39;/gi, "'"));
const parseName = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return '';
  if (/^<[^>]+>$/.test(raw)) return '';
  const angle = raw.match(/^(.*?)\s*<[^>]+>$/);
  if (angle?.[1]) return angle[1].replace(/^"|"$/g, '').trim();
  const email = normalizeEmail(raw);
  if (!email) return raw;
  return raw === email ? email.replace(/@.*$/, '').replace(/[._-]+/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase()) : raw;
};
const parseAddressList = (value) => String(value ?? '')
  .split(/,(?=(?:[^"]*"[^"]*")*[^"]*$)/)
  .map((entry) => entry.trim())
  .filter(Boolean)
  .map((entry) => ({
    raw: entry,
    email: normalizeEmail(entry),
    name: parseName(entry),
  }))
  .filter((entry) => entry.email);
const getHeader = (message, name) => {
  const direct = message?.[name];
  if (direct !== undefined && direct !== null && String(direct).trim()) {
    return String(direct).trim();
  }
  const directKey = Object.keys(message ?? {}).find((key) => key.toLowerCase() === String(name ?? '').toLowerCase());
  if (directKey && String(message?.[directKey] ?? '').trim()) {
    return String(message[directKey]).trim();
  }
  const headers = message?.payload?.headers ?? [];
  const found = headers.find((header) => String(header?.name ?? '').toLowerCase() === name.toLowerCase());
  return String(found?.value ?? '').trim();
};
const extractBodies = (payload) => {
  const parts = [];
  const walk = (node) => {
    if (!node) return;
    if (node.body?.data) parts.push(node);
    for (const child of node.parts ?? []) walk(child);
  };
  walk(payload);
  const plainPart = parts.find((part) => String(part?.mimeType ?? '').toLowerCase() === 'text/plain');
  const htmlPart = parts.find((part) => String(part?.mimeType ?? '').toLowerCase() === 'text/html');
  const plain = plainPart ? cleanText(decodeBase64Url(plainPart.body.data)) : '';
  const html = htmlPart ? decodeBase64Url(htmlPart.body.data) : '';
  return { plain, html };
};
const parseSentAt = (message) => {
  const internalDate = Number.parseInt(String(message?.internalDate ?? ''), 10);
  if (Number.isFinite(internalDate) && internalDate > 0) return new Date(internalDate).toISOString();
  const dateHeader = getHeader(message, 'Date');
  if (dateHeader) {
    const parsed = Date.parse(dateHeader);
    if (!Number.isNaN(parsed)) return new Date(parsed).toISOString();
  }
  return null;
};
const stripSubjectPrefixes = (value) => String(value ?? '')
  .replace(/^(\s*(re|fw|fwd)\s*:\s*)+/i, '')
  .trim();
const extractForwardedCandidate = (value) => {
  const text = String(value ?? '');
  if (!text.trim()) return null;
  const fromMatch = text.match(/(?:^|\n)From:\s*(.+?)(?:\n|$)/i);
  const wroteMatch = text.match(/(?:^|\n)On .+?([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}|[^<\n]+<[^>\n]+>) wrote:/i);
  const raw = String(fromMatch?.[1] ?? wroteMatch?.[1] ?? '').trim();
  if (!raw) return null;
  const email = normalizeEmail(raw);
  if (!email || internalEmails.has(email)) return null;
  return {
    raw,
    email,
    name: parseName(raw),
  };
};
const messages = Array.isArray(thread.messages) ? thread.messages.slice() : [];
messages.sort((left, right) => {
  const leftAt = Date.parse(parseSentAt(left) || '') || 0;
  const rightAt = Date.parse(parseSentAt(right) || '') || 0;
  return leftAt - rightAt;
});
const parsedMessages = messages.map((message) => {
  const fromRaw = getHeader(message, 'From');
  const toRaw = getHeader(message, 'To');
  const ccRaw = getHeader(message, 'Cc');
  const replyToRaw = getHeader(message, 'Reply-To');
  const subjectRaw = getHeader(message, 'Subject') || thread.snippet || 'Email case';
  const messageIdHeader = getHeader(message, 'Message-ID');
  const sentAt = parseSentAt(message);
  const body = extractBodies(message.payload);
  const bodyText = body.plain || stripHtml(body.html) || cleanText(message.snippet);
  const bodyHtml = body.html || null;
  return {
    gmail_message_id: String(message?.id ?? '').trim() || null,
    gmail_thread_id: String(thread?.id ?? '').trim() || null,
    from_raw: fromRaw,
    from_email: normalizeEmail(fromRaw),
    from_name: parseName(fromRaw),
    to_raw: toRaw,
    to_list: parseAddressList(toRaw),
    cc_raw: ccRaw,
    cc_list: parseAddressList(ccRaw),
    reply_to_raw: replyToRaw,
    reply_to_list: parseAddressList(replyToRaw),
    subject: subjectRaw,
    title_subject: stripSubjectPrefixes(subjectRaw) || 'Email case',
    body_text: bodyText || null,
    body_html: bodyHtml,
    sent_at: sentAt,
    message_id_header: messageIdHeader || null,
    snippet: cleanText(message?.snippet ?? ''),
  };
});
const externalCandidates = [];
const seenCandidateEmails = new Set();
const pushCandidate = (candidate) => {
  const email = normalizeEmail(candidate?.email ?? candidate?.raw ?? '');
  if (!email || internalEmails.has(email) || seenCandidateEmails.has(email)) return;
  seenCandidateEmails.add(email);
  externalCandidates.push({
    ...candidate,
    email,
  });
};
parsedMessages.forEach((message) => {
  pushCandidate(extractForwardedCandidate(message.body_text));
  pushCandidate(extractForwardedCandidate(message.body_html));
  pushCandidate({
    email: message.from_email,
    name: message.from_name || parseName(message.from_raw),
    raw: message.from_raw,
  });
  [...message.reply_to_list, ...message.to_list, ...message.cc_list]
    .forEach((entry) => pushCandidate(entry));
});
let contactEmail = '';
let contactName = '';
for (const candidate of externalCandidates) {
  if (!candidate.email) continue;
  contactEmail = candidate.email;
  contactName = candidate.name || parseName(candidate.raw) || contactEmail;
  break;
}
if (!contactEmail && parsedMessages[0]?.from_email) contactEmail = parsedMessages[0].from_email;
if (!contactName) contactName = parsedMessages[0]?.from_name || contactEmail || 'Unknown contact';
const title = parsedMessages.find((message) => message.title_subject)?.title_subject || 'Email case';
const messageRows = parsedMessages.map((message) => {
  const outboundTargetEmails = [...message.to_list, ...message.cc_list].map((entry) => entry.email);
  const direction = message.from_email && contactEmail && message.from_email === contactEmail
    ? 'incoming'
    : internalEmails.has(message.from_email)
      ? 'outgoing'
      : (outboundTargetEmails.includes(contactEmail) ? 'outgoing' : 'incoming');
  return {
    direction,
    subject: message.subject || title,
    body_html: message.body_html,
    body_text: message.body_text,
    recipients: {
      from: message.from_raw || null,
      to: message.to_raw || null,
      cc: message.cc_raw || null,
      reply_to: message.reply_to_raw || null,
    },
    gmail_message_id: message.gmail_message_id,
    gmail_thread_id: message.gmail_thread_id,
    sent_at: message.sent_at,
    metadata: {
      source_label: labelName,
      from_email: message.from_email || null,
      from_name: message.from_name || null,
      message_id_header: message.message_id_header,
      snippet: message.snippet || null,
      imported_via: 'gmail-case-sync',
    },
  };
});
const inboundTimes = messageRows.filter((row) => row.direction === 'incoming' && row.sent_at).map((row) => row.sent_at).sort();
const outboundTimes = messageRows.filter((row) => row.direction === 'outgoing' && row.sent_at).map((row) => row.sent_at).sort();
const firstSentAt = messageRows.find((row) => row.sent_at)?.sent_at || null;
const lastInboundAt = inboundTimes.length ? inboundTimes[inboundTimes.length - 1] : null;
const lastOutboundAt = outboundTimes.length ? outboundTimes[outboundTimes.length - 1] : null;
const caseMetadata = {
  gmail_thread_id: String(thread?.id ?? '').trim() || null,
  gmail_history_id: String(thread?.historyId ?? '').trim() || null,
  gmail_status_label: labelName || null,
  imported_via: 'gmail-case-sync',
  last_gmail_sync_at: new Date().toISOString(),
};
const timestampExpr = (column, value) => value
  ? `COALESCE(GREATEST(${column}, ${sqlLiteral(value)}::timestamptz), ${column}, ${sqlLiteral(value)}::timestamptz)`
  : column;
const threadIdSql = sqlLiteral(String(thread?.id ?? ''));
const firstSentAtSql = firstSentAt ? `${sqlLiteral(firstSentAt)}::timestamptz` : 'now()';
const lastInboundSql = lastInboundAt ? `${sqlLiteral(lastInboundAt)}::timestamptz` : 'NULL';
const lastOutboundSql = lastOutboundAt ? `${sqlLiteral(lastOutboundAt)}::timestamptz` : 'NULL';
const hasContactEmail = Boolean(contactEmail);
const hasContactName = Boolean(contactName && contactName !== 'Unknown contact');
const contactLookupConditions = [];
if (hasContactEmail) contactLookupConditions.push(`lower(COALESCE(c.email_address, '')) = lower(${sqlLiteral(contactEmail)})`);
if (hasContactName) contactLookupConditions.push(`lower(COALESCE(c.payer_name, '')) = lower(${sqlLiteral(contactName)})`);
const contactLookupWhere = contactLookupConditions.length ? contactLookupConditions.join(' OR ') : 'FALSE';
const resolvedNameExpr = `COALESCE((SELECT resolved_contact_name FROM matched_contact), ${sqlLiteral(contactName || 'Unknown contact')})`;
const resolvedEmailExpr = `COALESCE((SELECT resolved_contact_email FROM matched_contact), ${sqlLiteral(contactEmail || null)})`;
const resolvedPhoneExpr = `COALESCE((SELECT resolved_contact_phone FROM matched_contact), NULL)`;
const missingNameExpr = "COALESCE(NULLIF(trim(c.contact_name), ''), '') = '' OR lower(trim(c.contact_name)) IN ('unknown contact', 'unknown')";
const missingEmailExpr = "COALESCE(NULLIF(trim(c.contact_email), ''), '') = ''";
const missingPhoneExpr = "COALESCE(NULLIF(trim(c.contact_phone), ''), '') = ''";
const sql = [
  'WITH existing_case AS (',
  '  SELECT c.id',
  '  FROM public.cases c',
  `  WHERE COALESCE(c.metadata ->> 'gmail_thread_id', '') = ${threadIdSql}`,
  '  UNION ALL',
  '  SELECT ce.case_id',
  '  FROM public.case_emails ce',
  `  WHERE ce.gmail_thread_id = ${threadIdSql}`,
  '  LIMIT 1',
  '), matched_contact AS (',
