  '     OR NOT EXISTS (SELECT 1 FROM public.case_emails existing WHERE existing.gmail_message_id = message_rows.gmail_message_id)',
  '  RETURNING id',
  ')',
  'SELECT (SELECT id::text FROM target_case) AS case_id,',
  `       ${sqlLiteral(labelName)} AS source_label,`,
  '       (SELECT COUNT(*)::int FROM inserted_messages) AS inserted_messages;',
]
  .filter(Boolean)
